import { AIChat } from './components/AIChat';
import { FundamentalsPanel } from './components/FundamentalsPanel';
import { Header } from './components/Header';
import { PriceChart } from './components/PriceChart';
import { QuotePanel } from './components/QuotePanel';
import { SearchBar } from './components/SearchBar';
import { SkeletonCard } from './components/Skeleton';
import { Watchlist } from './components/Watchlist';
import { useStockData } from './hooks/useStockData';
import { useAppStore } from './store/appStore';

const App = () => {
  const {
    selectedSymbol,
    watchlist,
    refreshIntervalSec,
    setSelectedSymbol,
    addToWatchlist,
    removeFromWatchlist,
    setRefreshIntervalSec,
  } = useAppStore();

  const { quote, history, fundamentals, loading, error } = useStockData(selectedSymbol, refreshIntervalSec);

  return (
    <main className="mx-auto max-w-7xl p-4 md:p-6">
      <Header />

      <div className="mb-4 grid gap-4 lg:grid-cols-[2fr_1fr]">
        <SearchBar onSelect={setSelectedSymbol} />
        <section className="panel flex items-center justify-between gap-3 animate-riseIn">
          <label htmlFor="refresh" className="text-sm text-slate-300">
            Live refresh interval
          </label>
          <select
            id="refresh"
            value={refreshIntervalSec}
            onChange={(event) => setRefreshIntervalSec(Number(event.target.value))}
            className="rounded border border-bloomberg-600 bg-bloomberg-900 px-2 py-1 text-sm"
          >
            <option value={15}>15s</option>
            <option value={30}>30s</option>
            <option value={60}>60s</option>
          </select>
        </section>
      </div>

      {error && (
        <section className="mb-4 rounded-lg border border-bloomberg-negative/40 bg-bloomberg-negative/10 p-3 text-sm text-red-200">
          {error}
        </section>
      )}

      {loading && (
        <section className="card-grid mb-4">
          <SkeletonCard />
          <SkeletonCard />
          <SkeletonCard />
        </section>
      )}

      {!loading && quote && fundamentals && (
        <>
          <section className="mb-4 card-grid">
            <QuotePanel quote={quote} />
            <FundamentalsPanel fundamentals={fundamentals} />
            <Watchlist
              items={watchlist}
              selectedSymbol={selectedSymbol}
              onSelect={setSelectedSymbol}
              onAdd={addToWatchlist}
              onRemove={removeFromWatchlist}
            />
          </section>
          <section className="mb-4">
            <PriceChart data={history} />
          </section>
        </>
      )}

      <section className="mb-4">
        <AIChat />
      </section>
    </main>
  );
};

export default App;
