import { useEffect, useState } from 'react';
import { api } from '../services/api';
import type { SearchTickerResult } from '../types/stock';
import { useDebounce } from './useDebounce';

export const useTickerSearch = (query: string): {
  results: SearchTickerResult[];
  loading: boolean;
  error: string | null;
} => {
  const debounced = useDebounce(query, 350);
  const [results, setResults] = useState<SearchTickerResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!debounced || debounced.trim().length < 1) {
      setResults([]);
      setError(null);
      return;
    }

    let cancelled = false;

    const run = async (): Promise<void> => {
      try {
        setLoading(true);
        setError(null);
        const next = await api.searchTickers(debounced.trim());
        if (!cancelled) {
          setResults(next);
        }
      } catch (err) {
        if (!cancelled) {
          setError(err instanceof Error ? err.message : 'Failed to search tickers');
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };

    void run();
    return () => {
      cancelled = true;
    };
  }, [debounced]);

  return { results, loading, error };
};
