import { create } from 'zustand';

const STORAGE_KEY = 'stocksense-settings';

export interface AppStoreState {
  selectedSymbol: string;
  watchlist: string[];
  refreshIntervalSec: number;
  setSelectedSymbol: (symbol: string) => void;
  addToWatchlist: (symbol: string) => void;
  removeFromWatchlist: (symbol: string) => void;
  setRefreshIntervalSec: (seconds: number) => void;
}

interface PersistedState {
  selectedSymbol: string;
  watchlist: string[];
  refreshIntervalSec: number;
}

const readPersisted = (): PersistedState | null => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return null;
    }
    return JSON.parse(raw) as PersistedState;
  } catch {
    return null;
  }
};

const persist = (state: PersistedState): void => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const useAppStore = create<AppStoreState>((set, get) => {
  const persisted = typeof window !== 'undefined' ? readPersisted() : null;

  return {
    selectedSymbol: persisted?.selectedSymbol || 'AAPL',
    watchlist: persisted?.watchlist || ['AAPL', 'MSFT', 'NVDA'],
    refreshIntervalSec: persisted?.refreshIntervalSec || 30,
    setSelectedSymbol: (symbol) => {
      const normalized = symbol.toUpperCase();
      set({ selectedSymbol: normalized });
      const next = get();
      persist({
        selectedSymbol: next.selectedSymbol,
        watchlist: next.watchlist,
        refreshIntervalSec: next.refreshIntervalSec,
      });
    },
    addToWatchlist: (symbol) => {
      const normalized = symbol.toUpperCase();
      const current = get().watchlist;
      if (current.includes(normalized)) {
        return;
      }
      set({ watchlist: [...current, normalized] });
      const next = get();
      persist({
        selectedSymbol: next.selectedSymbol,
        watchlist: next.watchlist,
        refreshIntervalSec: next.refreshIntervalSec,
      });
    },
    removeFromWatchlist: (symbol) => {
      set({ watchlist: get().watchlist.filter((item) => item !== symbol.toUpperCase()) });
      const next = get();
      persist({
        selectedSymbol: next.selectedSymbol,
        watchlist: next.watchlist,
        refreshIntervalSec: next.refreshIntervalSec,
      });
    },
    setRefreshIntervalSec: (seconds) => {
      set({ refreshIntervalSec: seconds });
      const next = get();
      persist({
        selectedSymbol: next.selectedSymbol,
        watchlist: next.watchlist,
        refreshIntervalSec: next.refreshIntervalSec,
      });
    },
  };
});
