import { useEffect, useMemo, useState } from 'react';
import { api } from '../services/api';
import type { Fundamentals, HistoricalPoint, StockQuote } from '../types/stock';

interface StockDataState {
  quote: StockQuote | null;
  history: HistoricalPoint[];
  fundamentals: Fundamentals | null;
  loading: boolean;
  error: string | null;
}

export const useStockData = (symbol: string, refreshIntervalSec: number): StockDataState => {
  const [quote, setQuote] = useState<StockQuote | null>(null);
  const [history, setHistory] = useState<HistoricalPoint[]>([]);
  const [fundamentals, setFundamentals] = useState<Fundamentals | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;

    const load = async (): Promise<void> => {
      try {
        setError(null);
        setLoading(true);

        const [quoteResult, historyResult, fundamentalsResult] = await Promise.all([
          api.getQuote(symbol),
          api.getHistorical(symbol),
          api.getFundamentals(symbol),
        ]);

        if (cancelled) {
          return;
        }

        setQuote(quoteResult);
        setHistory(historyResult);
        setFundamentals(fundamentalsResult);
      } catch (err) {
        if (!cancelled) {
          setError(err instanceof Error ? err.message : 'Failed to load market data');
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };

    void load();
    const timer = window.setInterval(() => {
      void load();
    }, Math.max(10, refreshIntervalSec) * 1000);

    return () => {
      cancelled = true;
      window.clearInterval(timer);
    };
  }, [symbol, refreshIntervalSec]);

  return useMemo(
    () => ({ quote, history, fundamentals, loading, error }),
    [quote, history, fundamentals, loading, error]
  );
};
