import React from 'react';
import { Area, AreaChart, CartesianGrid, ResponsiveContainer, Tooltip, XAxis, YAxis } from 'recharts';
import type { HistoricalPoint } from '../types/stock';
import { formatDateShort } from '../utils/format';

interface PriceChartProps {
  data: HistoricalPoint[];
}

export const PriceChart = React.memo(({ data }: PriceChartProps) => {
  return (
    <section className="panel animate-riseIn">
      <div className="mb-2 flex items-center justify-between">
        <h2 className="text-lg font-semibold text-slate-100">5-Year Trend</h2>
        <span className="text-xs text-slate-400">Monthly candles (close)</span>
      </div>
      <div className="h-72 w-full">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={data} margin={{ top: 12, right: 12, left: 0, bottom: 0 }}>
            <defs>
              <linearGradient id="priceGradient" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#f6a31a" stopOpacity={0.6} />
                <stop offset="95%" stopColor="#f6a31a" stopOpacity={0.02} />
              </linearGradient>
            </defs>
            <CartesianGrid stroke="rgba(148,163,184,0.12)" strokeDasharray="3 3" />
            <XAxis
              dataKey="date"
              tick={{ fill: '#cbd5e1', fontSize: 11 }}
              tickFormatter={(value: string) => formatDateShort(value)}
              minTickGap={20}
            />
            <YAxis tick={{ fill: '#cbd5e1', fontSize: 11 }} domain={["auto", "auto"]} />
            <Tooltip
              contentStyle={{
                backgroundColor: '#111521',
                border: '1px solid #3b4d74',
                borderRadius: '8px',
                color: '#f8fafc',
              }}
            />
            <Area type="monotone" dataKey="close" stroke="#f6a31a" fill="url(#priceGradient)" strokeWidth={2} />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </section>
  );
});
