interface WatchlistProps {
  items: string[];
  selectedSymbol: string;
  onSelect: (symbol: string) => void;
  onRemove: (symbol: string) => void;
  onAdd: (symbol: string) => void;
}

export const Watchlist = ({ items, selectedSymbol, onSelect, onRemove, onAdd }: WatchlistProps) => {
  return (
    <section className="panel animate-riseIn">
      <div className="mb-3 flex items-center justify-between">
        <h2 className="text-lg font-semibold text-slate-100">Watchlist</h2>
        <button
          type="button"
          onClick={() => {
            const input = window.prompt('Add ticker (e.g., AAPL, 0700.HK, RELIANCE.NS)');
            if (input) {
              onAdd(input.trim().toUpperCase());
            }
          }}
          className="rounded bg-bloomberg-accent px-2 py-1 text-xs font-medium text-black"
        >
          Add
        </button>
      </div>
      <ul className="space-y-2">
        {items.map((symbol) => (
          <li key={symbol} className="flex items-center justify-between rounded bg-bloomberg-900/70 px-2 py-1">
            <button
              type="button"
              onClick={() => onSelect(symbol)}
              className={`text-sm ${selectedSymbol === symbol ? 'font-semibold text-bloomberg-accent' : 'text-slate-200'}`}
            >
              {symbol}
            </button>
            <button
              type="button"
              onClick={() => onRemove(symbol)}
              className="text-xs text-slate-400 hover:text-bloomberg-negative"
            >
              remove
            </button>
          </li>
        ))}
      </ul>
    </section>
  );
};
