export const formatCurrency = (value: number | undefined, currency = 'USD'): string => {
  if (value === undefined || Number.isNaN(value)) {
    return '-';
  }

  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency,
    maximumFractionDigits: value >= 1000 ? 0 : 2,
  }).format(value);
};

export const formatCompactNumber = (value: number | undefined): string => {
  if (value === undefined || Number.isNaN(value)) {
    return '-';
  }

  return new Intl.NumberFormat('en-US', {
    notation: 'compact',
    maximumFractionDigits: 2,
  }).format(value);
};

export const formatPercent = (value: number | undefined): string => {
  if (value === undefined || Number.isNaN(value)) {
    return '-';
  }

  return `${value.toFixed(2)}%`;
};

export const formatDateShort = (dateValue: string): string => {
  const date = new Date(dateValue);
  if (Number.isNaN(date.getTime())) {
    return dateValue;
  }

  return new Intl.DateTimeFormat('en-US', { month: 'short', year: '2-digit' }).format(date);
};
