import React from 'react';
import type { StockQuote } from '../types/stock';
import { formatCompactNumber, formatCurrency, formatPercent } from '../utils/format';

interface QuotePanelProps {
  quote: StockQuote;
}

export const QuotePanel = React.memo(({ quote }: QuotePanelProps) => {
  const isPositive = quote.change >= 0;

  return (
    <section className="panel animate-riseIn">
      <div className="mb-2 flex items-center justify-between gap-3">
        <h2 className="text-lg font-semibold text-slate-100">{quote.symbol}</h2>
        <span className="rounded bg-bloomberg-700 px-2 py-1 text-xs text-slate-300">{quote.exchange}</span>
      </div>
      <p className="text-sm text-slate-400">{quote.shortName || quote.longName || 'Company'}</p>
      <p className="kpi mt-2">{formatCurrency(quote.price, quote.currency)}</p>
      <p className={`mt-1 text-sm font-medium ${isPositive ? 'text-bloomberg-positive' : 'text-bloomberg-negative'}`}>
        {formatCurrency(quote.change, quote.currency)} ({formatPercent(quote.changePercent)})
      </p>
      <dl className="mt-4 grid grid-cols-2 gap-2 text-sm">
        <div>
          <dt className="text-slate-400">Day Range</dt>
          <dd className="text-slate-100">
            {formatCurrency(quote.dayLow, quote.currency)} - {formatCurrency(quote.dayHigh, quote.currency)}
          </dd>
        </div>
        <div>
          <dt className="text-slate-400">Volume</dt>
          <dd className="text-slate-100">{formatCompactNumber(quote.volume)}</dd>
        </div>
      </dl>
    </section>
  );
});
