import type { AIAnalysis } from '../types/ai';
import type { Fundamentals, HistoricalPoint, SearchTickerResult, StockQuote } from '../types/stock';

const API_BASE = (import.meta.env.VITE_API_BASE_URL as string | undefined) || '';

const buildUrl = (path: string): string => {
  if (!API_BASE) {
    return path;
  }

  return `${API_BASE.replace(/\/$/, '')}${path}`;
};

const request = async <T>(path: string, options?: RequestInit): Promise<T> => {
  const response = await fetch(buildUrl(path), {
    headers: {
      'Content-Type': 'application/json',
    },
    ...options,
  });

  if (!response.ok) {
    const message = await response.text();
    throw new Error(message || `Request failed with status ${response.status}`);
  }

  return (await response.json()) as T;
};

export const api = {
  getQuote: (symbol: string) => request<StockQuote>(`/api/quote?symbol=${encodeURIComponent(symbol)}`),
  getHistorical: (symbol: string) =>
    request<HistoricalPoint[]>(`/api/history?symbol=${encodeURIComponent(symbol)}&range=5y&interval=1mo`),
  getFundamentals: (symbol: string) =>
    request<Fundamentals>(`/api/fundamentals?symbol=${encodeURIComponent(symbol)}`),
  searchTickers: (query: string) =>
    request<SearchTickerResult[]>(`/api/search?query=${encodeURIComponent(query)}`),
  chatAssistant: (message: string) =>
    request<{ analysis: AIAnalysis; quoteSnapshot?: StockQuote; responseText: string }>('/api/ai-assistant', {
      method: 'POST',
      body: JSON.stringify({ message }),
    }),
};
