import React from 'react';
import type { Fundamentals } from '../types/stock';
import { formatCompactNumber, formatPercent } from '../utils/format';

interface FundamentalsPanelProps {
  fundamentals: Fundamentals;
}

export const FundamentalsPanel = React.memo(({ fundamentals }: FundamentalsPanelProps) => {
  return (
    <section className="panel animate-riseIn">
      <h2 className="text-lg font-semibold text-slate-100">Fundamentals</h2>
      <dl className="mt-3 grid grid-cols-2 gap-3 text-sm">
        <div>
          <dt className="text-slate-400">P/E Ratio</dt>
          <dd className="text-slate-100">{fundamentals.peRatio?.toFixed(2) ?? '-'}</dd>
        </div>
        <div>
          <dt className="text-slate-400">Market Cap</dt>
          <dd className="text-slate-100">{formatCompactNumber(fundamentals.marketCap)}</dd>
        </div>
        <div>
          <dt className="text-slate-400">ROE</dt>
          <dd className="text-slate-100">{formatPercent(fundamentals.roe)}</dd>
        </div>
        <div>
          <dt className="text-slate-400">Dividend Yield</dt>
          <dd className="text-slate-100">{formatPercent(fundamentals.dividendYield)}</dd>
        </div>
      </dl>
    </section>
  );
});
