import { useMemo, useState } from 'react';
import { api } from '../services/api';
import type { AIMessage } from '../types/ai';

const getRecommendationColor = (recommendation: string): string => {
  if (recommendation === 'BUY') {
    return 'text-bloomberg-positive';
  }
  if (recommendation === 'SELL') {
    return 'text-bloomberg-negative';
  }
  return 'text-bloomberg-accent';
};

export const AIChat = () => {
  const [messages, setMessages] = useState<AIMessage[]>([]);
  const [input, setInput] = useState('Analyze NVDA and tell me if this is a buy right now.');
  const [loading, setLoading] = useState(false);

  const canSend = useMemo(() => !loading && input.trim().length > 0, [input, loading]);

  const send = async (): Promise<void> => {
    const trimmed = input.trim();
    if (!trimmed) {
      return;
    }

    const userMessage: AIMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      content: trimmed,
      createdAt: new Date().toISOString(),
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput('');
    setLoading(true);

    try {
      const response = await api.chatAssistant(trimmed);
      const assistantMessage: AIMessage = {
        id: crypto.randomUUID(),
        role: 'assistant',
        content: response.responseText,
        createdAt: new Date().toISOString(),
        analysis: response.analysis,
        quoteSnapshot: response.quoteSnapshot,
      };
      setMessages((prev) => [...prev, assistantMessage]);
    } catch (err) {
      setMessages((prev) => [
        ...prev,
        {
          id: crypto.randomUUID(),
          role: 'assistant',
          content: err instanceof Error ? err.message : 'Failed to query AI assistant',
          createdAt: new Date().toISOString(),
        },
      ]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="panel animate-riseIn">
      <h2 className="text-lg font-semibold text-slate-100">StockSense AI Assistant</h2>
      <p className="mt-1 text-xs text-slate-400">
        Natural language prompts with ticker detection + live quote tool-calling + structured Buy/Hold/Sell output.
      </p>

      <div className="mt-3 max-h-96 space-y-3 overflow-auto rounded-lg border border-bloomberg-600 bg-bloomberg-900/70 p-3">
        {messages.length === 0 && <p className="text-sm text-slate-400">Ask about any supported stock ticker to begin.</p>}
        {messages.map((message) => (
          <article key={message.id} className="rounded border border-bloomberg-700/70 bg-bloomberg-800/70 p-3">
            <p className="text-xs uppercase tracking-wide text-slate-400">{message.role}</p>
            <p className="mt-1 text-sm text-slate-100">{message.content}</p>
            {message.analysis && (
              <div className="mt-3 rounded border border-bloomberg-600/70 bg-bloomberg-900/60 p-2 text-xs">
                <p className={`font-semibold ${getRecommendationColor(message.analysis.recommendation)}`}>
                  {message.analysis.symbol}: {message.analysis.recommendation} ({message.analysis.confidence}% confidence)
                </p>
                <p className="mt-1 text-slate-300">{message.analysis.summary}</p>
              </div>
            )}
          </article>
        ))}
      </div>

      <div className="mt-3 flex gap-2">
        <input
          value={input}
          onChange={(event) => setInput(event.target.value)}
          placeholder="Analyze TSLA for long-term entry"
          className="flex-1 rounded-md border border-bloomberg-600 bg-bloomberg-900 px-3 py-2 text-sm text-slate-100 outline-none ring-bloomberg-accent focus:ring-2"
        />
        <button
          type="button"
          onClick={() => {
            void send();
          }}
          disabled={!canSend}
          className="rounded-md bg-bloomberg-accent px-4 py-2 text-sm font-semibold text-black disabled:opacity-50"
        >
          {loading ? 'Thinking...' : 'Send'}
        </button>
      </div>
    </section>
  );
};
