import React from 'react';

interface ErrorBoundaryState {
  hasError: boolean;
  message: string;
}

interface ErrorBoundaryProps {
  children: React.ReactNode;
}

export class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  state: ErrorBoundaryState = {
    hasError: false,
    message: '',
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, message: error.message };
  }

  componentDidCatch(error: Error, info: React.ErrorInfo): void {
    console.error('ErrorBoundary caught an error', error, info);
  }

  private onReload = (): void => {
    window.location.reload();
  };

  render(): React.ReactNode {
    if (this.state.hasError) {
      return (
        <main className="flex min-h-screen items-center justify-center p-4">
          <section className="panel max-w-xl text-center">
            <h1 className="mb-2 text-2xl font-semibold text-bloomberg-accent">StockSense AI encountered an error</h1>
            <p className="mb-4 text-sm text-slate-300">{this.state.message || 'Unexpected runtime error'}</p>
            <button
              type="button"
              onClick={this.onReload}
              className="rounded-md bg-bloomberg-accent px-4 py-2 text-sm font-medium text-black"
            >
              Reload Application
            </button>
          </section>
        </main>
      );
    }

    return this.props.children;
  }
}
