import { useMemo, useState } from 'react';
import { useTickerSearch } from '../hooks/useTickerSearch';
import { EXCHANGE_SUFFIX_HELP } from '../utils/exchanges';

interface SearchBarProps {
  onSelect: (symbol: string) => void;
}

export const SearchBar = ({ onSelect }: SearchBarProps) => {
  const [query, setQuery] = useState('');
  const { results, loading } = useTickerSearch(query);

  const helperText = useMemo(() => Object.values(EXCHANGE_SUFFIX_HELP).join('  |  '), []);

  return (
    <section className="panel animate-riseIn">
      <label htmlFor="ticker-search" className="mb-2 block text-sm font-medium text-slate-200">
        Search Global Tickers
      </label>
      <input
        id="ticker-search"
        value={query}
        onChange={(event) => setQuery(event.target.value)}
        placeholder="Try AAPL, 0700.HK, AIR.PA, RELIANCE.NS"
        className="w-full rounded-md border border-bloomberg-600 bg-bloomberg-900 px-3 py-2 text-sm text-slate-100 outline-none ring-bloomberg-accent transition focus:ring-2"
      />
      <p className="mt-2 text-xs text-slate-400">Exchange suffix examples: {helperText}</p>
      {loading && <p className="mt-2 text-xs text-slate-400">Searching...</p>}
      {!!results.length && (
        <ul className="mt-3 max-h-56 overflow-auto rounded-lg border border-bloomberg-600 bg-bloomberg-900/95">
          {results.slice(0, 8).map((item) => (
            <li key={`${item.symbol}-${item.exchange}`}>
              <button
                type="button"
                className="w-full border-b border-bloomberg-700 px-3 py-2 text-left text-sm hover:bg-bloomberg-700/40"
                onClick={() => {
                  onSelect(item.symbol);
                  setQuery('');
                }}
              >
                <span className="font-semibold text-slate-100">{item.symbol}</span>
                <span className="ml-2 text-slate-300">{item.name}</span>
                <span className="ml-2 text-xs text-slate-500">{item.exchange}</span>
              </button>
            </li>
          ))}
        </ul>
      )}
    </section>
  );
};
